import{_ as n,o as t,c as e,a2 as i}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F04: 業外收支純度與收益質量","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F04_業外收支純度與收益質量_投資研究員.md","filePath":"32Ｑ題本＿重要/財務組/F04_業外收支純度與收益質量_投資研究員.md"}'),r={name:"32Ｑ題本＿重要/財務組/F04_業外收支純度與收益質量_投資研究員.md"};function l(s,o,a,g,c,d){return t(),e("div",null,[...o[0]||(o[0]=[i('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f04-業外收支純度與收益質量" tabindex="-1">F04: 業外收支純度與收益質量 <a class="header-anchor" href="#f04-業外收支純度與收益質量" aria-label="Permalink to &quot;F04: 業外收支純度與收益質量&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F04</li><li><strong>題目：</strong> 業外收支 (Non-Operating) 規模與組成細項為何？是長期投資收益還是匯兌/利息等雜項損益？是否存在獲利虛胖風險？</li><li><strong>推薦專家：</strong> 投資研究員 (<code>finance-investment-researcher</code>)</li><li><strong>推薦理由：</strong> 專精於「獲利可持續性 (Earnings Sustainability)」與「收益質量分析」。擅長拆解權益法投資、匯率變動與各類金融商品的實質損益。投研員的任務是穿透財務表象，還原出扣除「一籃子雜訊」後的真實估值基座。</li><li><strong>意圖：</strong> 執行「獲利純粹度與評價品質審計」，識別非核心業務損益對 EPS 的貢獻佔比，判定公司獲利是否具備「長期持有的穩定競爭力」。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockFinancialStatements</code> 提取「營業外收入及支出合計 (Non-Operating Income and Expenses)」、「利息收入 (Interest Income)」以及「其他利益及損失 (Other Gains and Losses)」。</li><li><strong>【外部事實檢索：央行/匯率預警】</strong>：若匯兌損益佔比大，智慧體必須檢索當季「台幣/美金匯率走勢」以判定損益是否具備迴轉風險。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱「財務報告附註 -&gt; 營業外收入及支出」，詳列其權益法認列之被投資公司表現。</li></ol></li><li><strong>邏輯：</strong> 執行「收益質量分類算法」——區分定常性的「權益法收益/利息」與偶然性的「匯兌損益/資產減損」；判定獲利之「估值折價或溢價」。</li><li><strong>來源：</strong> <code>FinMind (業外損益細項)</code>, <code>MOPS 分部資訊 (權益法公司清單)</code>, <code>公司年報 (業外損益附註)</code>, <code>財經新聞 (匯率敏感度報告)</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>取數據</strong>：<code>python3 數據採集器.py finance [股號]</code> → 抓 <code>TotalNonoperatingIncomeAndExpense</code>、<code>OperatingIncome</code>、<code>PreTaxIncome</code></li><li><strong>計算</strong>：業外佔比 = 業外收支 / 稅前淨利。若 &gt;10% 需深挖；&gt;20% = 獲利結構脆弱</li><li><strong>判讀</strong>：業外主要來源（利息收入？匯率？資產處分？）是否一次性</li><li><strong>年報補充</strong>：用 <code>pdf</code> 工具從年報提取「業外損益附註」確認細項</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【業外組成事實穿透】</strong>：智慧體<strong>必須</strong>列出業外收入的前三大組成（如：匯兌、利息、股利、處分）。禁止在未細分科目時進行優劣判定。</li><li><strong>【匯兌含金量審核】</strong>：若匯率相關收益佔淨利比重 &gt; 25%，智慧體必須強制發出「獲利含金量極低」警訊。</li><li><strong>【權益法戰略對比】</strong>：分析轉投資公司是否與主業相關。若業外獲利來自不相關之金融操盤收益，應標註為「投資公司化」之治理警訊。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述約束】</strong>：絕對禁用「表現豐沛」、「損失巨大」。必須量化為具體的「業外貢獻比 % (Non-Op Matrix)」與「扣非後 EPS」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f04-專家答詢】投資研究員-finance-investment-researcher" tabindex="-1">【F04 專家答詢】投資研究員 (finance-investment-researcher) <a class="header-anchor" href="#【f04-專家答詢】投資研究員-finance-investment-researcher" aria-label="Permalink to &quot;【F04 專家答詢】投資研究員 (finance-investment-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「業外佔比+屬性鑑定」結構（例：本季獲利 X% 來自 [匯兌/利息/權益法]，本業獲利純度為 [高/低]，評價趨勢應採 [保守/積極] 觀點）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：業外收益來自穩定的核心業務相關權益法投資，且本業獲利佔比 &gt; 90%，顯示公司具備極佳的產業鏈轉投資眼光與透明的獲利結構。</li><li><strong>A (良)</strong>：業外結構單純（利息收入為主），無重大匯兌損失或衍生工具評價風險，獲利品質可控。</li><li><strong>B (持平)</strong>：獲利高度依賴匯兌利益或一次性處分利益，本業獲利出現萎縮，顯示獲利具備高度「隨機性」與「不可持續性」。</li></ul></li><li><strong>【答詢詳解】解析深度</strong>：依照以下三個維度回答： <ol><li><strong>收益結構透視 (Income Composition)</strong>：精確拆解並列出各項業外收支對 EPS 的具體貢獻。</li><li><strong>雜訊敏感度分析 (Noise Sensitivity)</strong>：評估當匯率或利率變動 1% 時，對淨利的邊際影響。</li><li><strong>可持續性評價 (Sustainability Audit)</strong>：判定該獲利在未來三季內是否具備「常態性再現」的機率。</li></ol></li><li><strong>【證據來源】數據溯源</strong>：必須精確列出 FinMind <code>financial</code> 業外明細科目與年報 P.XXX 投資附註。</li><li><strong>【專家評析】核心分析與洞察內容</strong>：特別關注「公允價值變動損益」。在市場波動期，這類未實現獲利可能在下一季瞬間轉為巨大減損，專家應在此處進行「未實現風險」之預警。判定這是「戰略性穩健 (Strategic Stability)」還是「短期性套利 (Short-term Arbitrage)」。</li></ul>',11)])])}const m=n(r,[["render",l]]);export{h as __pageData,m as default};
